"use client";

import { Blocks } from "lucide-react";

import type { LedgerEvent } from "@/lib/chainops/jsonStore";

type LedgerDrawerProps = {
  events: LedgerEvent[];
};

export default function LedgerDrawer({ events }: LedgerDrawerProps) {
  const visibleEvents = [...events].sort((a, b) => b.eventId - a.eventId);

  return (
    <section className="border-t border-neutral-200 bg-white">
      <div className="flex items-center justify-between gap-16 px-18 py-12">
        <div className="flex items-center gap-8">
          <Blocks className="h-18 w-18 text-violet-700" />
          <h2 className="text-[15px] font-semibold text-neutral-950">
            Blockchain Audit Log
          </h2>
        </div>
        <span className="bg-neutral-100 px-8 py-4 text-[12px] text-neutral-700">
          {events.length} events
        </span>
      </div>

      <div className="max-h-[230px] overflow-auto border-t border-neutral-100">
        {visibleEvents.length ? (
          <div className="min-w-[860px]">
            <div className="grid grid-cols-[70px_210px_190px_190px_170px_1fr] gap-10 border-b border-neutral-100 bg-neutral-50 px-18 py-8 text-[11px] font-semibold uppercase text-neutral-500">
              <span>ID</span>
              <span>Event Type</span>
              <span>Project</span>
              <span>Entity</span>
              <span>Time</span>
              <span>Transaction / Local Index</span>
            </div>
            {visibleEvents.map((event) => (
              <div
                className="grid grid-cols-[70px_210px_190px_190px_170px_1fr] gap-10 border-b border-neutral-100 px-18 py-9 text-[12px] text-neutral-700"
                key={event.eventId}
              >
                <span className="font-mono text-neutral-950">#{event.eventId}</span>
                <span className="font-semibold text-neutral-950">{event.eventType}</span>
                <span className="font-mono">{event.projectId}</span>
                <span className="font-mono">{event.entityId}</span>
                <span>{new Date(event.timestamp).toLocaleString()}</span>
                <span className="font-mono">{event.transactionHash}</span>
              </div>
            ))}
          </div>
        ) : (
          <p className="px-18 py-16 text-[13px] text-neutral-600">
            No audit events have been written yet.
          </p>
        )}
      </div>
    </section>
  );
}
